text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI 테마 패키지 출시 준비도 점검",
    "participants": [
      "민준",
      "서연",
      "도윤",
      "하라"
    ],
    "decisions": [
      {
        "topic": "공개 출시 목표 시점",
        "decision": "스모크 테스트가 통과하는 경우 금요일 15:00 KST를 공개 출시 목표 시점으로 한다.",
        "certainty": "confirmed"
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 점검하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "certainty": "confirmed"
      }
    ],
    "non_decisions": {
      "rejected_proposals": [
        {
          "topic": "smoke-theme-pack.mjs 처리 방식",
          "proposal": "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 변경하자는 제안",
          "result": "기각됨"
        }
      ],
      "internal_stretch_goals": [
        {
          "topic": "수요일 출시안",
          "detail": "수요일 출시 제안은 내부 스트레치 목표일 뿐 최종 공개 출시 결정이 아니다."
        }
      ],
      "unassigned_or_not_finalized": [
        {
          "topic": "README 설치 단계 검토",
          "detail": "가능하면 목요일까지 검토하자는 의견은 있었으나 담당자는 지정되지 않았다."
        },
        {
          "topic": "하라의 타르볼 경로 확인",
          "detail": "민준의 스모크 결과 공유 이후 확인하기로 했으나 정확한 기한은 정해지지 않았다."
        }
      ]
    },
    "risks": [
      {
        "risk": "타르볼 경로가 잘못되면 출시가 지연될 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래된 상태라면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 출시 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "민준",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "도윤",
      "task": "금요일 12:00 KST까지 failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "미정",
      "task": "README 설치 단계를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시",
      "status": "미배정",
      "source_certainty": "mentioned_but_not_assigned"
    },
    {
      "owner": "하라",
      "task": "민준의 스모크 결과 공유 후 생성된 타르볼 경로를 확인한다.",
      "due": "미정",
      "status": "확정",
      "source_certainty": "confirmed_with_no_exact_deadline"
    }
  ],
  "followup_note": {
    "next_checks": [
      "민준의 스모크 테스트 통과 여부를 먼저 확인한다.",
      "스모크 결과 공유 후 하라의 타르볼 경로 점검 결과를 확인한다.",
      "도윤의 failure triage note 작성 완료 여부를 확인한다.",
      "README 설치 단계 검토 담당자 지정 필요 여부를 확인한다.",
      "최종 출시 승인 권한자와 릴리스 노트 기재 범위를 후속 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "지정되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "인라인 공개용 합성 픽스처에 없는 사실은 추가하지 않는다.",
    "확정 결정과 제안, 스트레치 목표, 위험, 미해결 질문을 구분해서 기록한다.",
    "고객, 예산, 보안, 장애, 법무 관련 사실은 언급된 내용이 없으므로 만들어 쓰지 않는다.",
    "담당자와 마감은 명시된 경우에만 기록하고, 없으면 미정 또는 미배정으로 둔다.",
    "수요일 출시안은 확정 일정이 아니라 내부 스트레치 목표로만 기록한다."
  ]
}
